import { _OverlayTooltip as OverlayTooltip } from '@dynatrace/strato-components/charts';

import { useGeoLayerTooltip } from '../../hooks/use-geo-layer-tooltip.js';
import type {
  ChoroplethLayerTooltipData,
  ChoroplethLayerTooltipHandler,
} from '../../types/tooltip.js';
import { isDefaultTooltipHandler } from '../../utils/tooltip-type-guards.js';

interface ChoroplethTooltipStatePayload {
  name: string;
  __color: string;
  __hoveredColor: string;
  data: Record<string, unknown>;
}

export interface ChoroplethLayerTooltipProps {
  tooltipTemplate?: ChoroplethLayerTooltipHandler;
  hidden?: boolean;
  symbolAlignment?: 'left' | 'right';
}

export const ChoroplethLayerTooltip = (props: ChoroplethLayerTooltipProps) => {
  const { tooltipTemplate, hidden, symbolAlignment } = props;

  const { data, inBounds, position } =
    useGeoLayerTooltip<ChoroplethTooltipStatePayload>('geoChoropleth');

  if (hidden || !tooltipTemplate || !inBounds || !position) {
    return null;
  }

  if (!data || !data[0]) {
    return null;
  }

  const { name, __color: color, data: customData } = data[0];
  const regionData: ChoroplethLayerTooltipData = {
    data: customData,
    name,
    color,
  };

  const template = tooltipTemplate(regionData);

  if (!template) {
    return null;
  }

  if (isDefaultTooltipHandler(tooltipTemplate)) {
    return template;
  }

  return (
    <OverlayTooltip
      legacyTemplate={template}
      symbolAlignment={symbolAlignment}
    />
  );
};

ChoroplethLayerTooltip['displayName'] = 'ChoroplethLayerTooltip';
